```class Solution {
    public int minChanges(int[] nums, int k) {
        int n = nums.length;
        int[] prefixXOR = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixXOR[i + 1] = prefixXOR[i] ^ nums[i];
        }
        int res = n;
        for (int i = 0; i <= n - k; i++) {
            int xor = prefixXOR[i + k] ^ prefixXOR[i];
            res = Math.min(res, k - (xor ^ prefixXOR[i + k - 1]));
        }
        return res;
    }
}```
